export const refinementVerdictV1Schema = {
  $schema: 'https://json-schema.org/draft/2020-12/schema',
  $id: 'https://ai-sdlc.io/schemas/v1alpha1/refinement-verdict.v1.schema.json',
  title: 'AI-SDLC RefinementVerdict',
  description:
    'Per-issue verdict produced by the Definition-of-Ready evaluator (RFC-0011 §5, §9.2). One file per evaluation; written to the calibration log and consumed by ingress shims (GitHub Action, Claude Code subagent, future Forge / Slack shims).',
  type: 'object',
  required: ['issueId', 'rubricVersion', 'overallVerdict', 'gates', 'signedAt', 'evaluatorVersion'],
  properties: {
    issueId: {
      type: 'string',
      minLength: 1,
      description: "Stable issue identifier (e.g. 'AISDLC-92', 'gh#42', 'forge-1234').",
    },
    rubricVersion: {
      type: 'string',
      enum: ['v1'],
      description:
        'Rubric version this verdict was scored against. Pinned so historical verdicts are interpretable after rubric revisions.',
    },
    overallVerdict: {
      type: 'string',
      enum: ['admit', 'needs-clarification'],
      description:
        "Composite verdict. 'admit' = pass DoR, advance to PPA. 'needs-clarification' = block + post questions.",
    },
    gates: {
      type: 'array',
      minItems: 1,
      maxItems: 7,
      description:
        'Per-gate verdict shape (RFC §4.1 — exactly 7 gates in v1; smaller arrays allowed for partial evaluations e.g. when an autoPassRule skips gates).',
      items: {
        type: 'object',
        required: ['gateId', 'verdict', 'confidence'],
        properties: {
          gateId: {
            type: 'integer',
            minimum: 1,
            maximum: 7,
            description:
              'Rubric gate number (1: AC binary-testable, 2: no markers, 3: refs resolve, 4: scope bounded, 5: surface named, 6: done-state describable, 7: no invisible deps).',
          },
          verdict: {
            type: 'string',
            enum: ['pass', 'fail', 'skip'],
            description:
              "Per-gate outcome. 'skip' = autoPassRule excluded this gate; 'fail' = gate produced a blocking finding; 'pass' = gate cleared.",
          },
          confidence: {
            type: 'string',
            enum: ['high', 'medium', 'low'],
            description:
              'Per-gate confidence (RFC §5.5, §13 Q4). low → escalate to human triager; medium → act + flag for spot-check; high → act on verdict.',
          },
          clarificationQuestion: {
            type: 'string',
            minLength: 1,
            description:
              "Optional single clarifying question the evaluator wants the author to answer. Only set when verdict='fail'.",
          },
          finding: {
            type: 'string',
            minLength: 1,
            description:
              "Optional human-readable finding describing why this gate failed (e.g. 'AC #2 not binary-testable').",
          },
          stage: {
            type: 'string',
            enum: ['A', 'B'],
            description:
              "Which evaluation stage produced this verdict (RFC §4.4). 'A' = deterministic regex / link / structure; 'B' = LLM semantic check.",
          },
        },
        additionalProperties: false,
      },
    },
    signedAt: {
      type: 'string',
      format: 'date-time',
      description: 'ISO-8601 timestamp at which the evaluator finalised this verdict.',
    },
    evaluatorVersion: {
      type: 'string',
      minLength: 1,
      description:
        'Semver / git-sha of the evaluator binary that produced this verdict. Used for calibration log cross-referencing (RFC §5.5).',
    },
    summary: {
      type: 'string',
      maxLength: 500,
      description: 'Optional one-sentence human-readable summary of the verdict.',
    },
    questions: {
      type: 'array',
      items: {
        type: 'string',
        minLength: 1,
      },
      description:
        'Aggregate clarifying questions for the comment-loop ingress to post (deduped, ordered).',
    },
    overallConfidence: {
      type: 'string',
      enum: ['high', 'medium', 'low'],
      description: 'Optional aggregate confidence across all gates (RFC §5.5).',
    },
  },
  additionalProperties: false,
} as const;

export const rfcSchema = {
  $schema: 'https://json-schema.org/draft/2020-12/schema',
  $id: 'https://ai-sdlc.io/schemas/v1alpha1/rfc.schema.json',
  title: 'AI-SDLC RFC Frontmatter',
  description:
    'YAML frontmatter convention for `spec/rfcs/RFC-NNNN-*.md` files. Defines the closed enum of `requiresDocs` values consumed by the docs-drift CI script (AISDLC-69.3). The full RFC body lives below the frontmatter as Markdown.',
  type: 'object',
  required: ['id', 'title', 'status', 'author', 'created', 'updated', 'requiresDocs'],
  additionalProperties: false,
  properties: {
    id: {
      type: 'string',
      pattern: '^RFC-[0-9]{4}$',
      description:
        'Canonical RFC identifier in the form `RFC-NNNN`. Must match the filename prefix (e.g. `RFC-0006-design-system-governance-v5-final.md` → `id: RFC-0006`).',
    },
    title: {
      type: 'string',
      minLength: 3,
      description: "Human-readable title (no `RFC-NNNN:` prefix — that's encoded in `id`).",
    },
    status: {
      type: 'string',
      enum: ['Draft', 'Under Review', 'Approved', 'Implemented', 'Final', 'Rejected', 'Withdrawn'],
      description:
        'Lifecycle status (legacy enum, retained for backward compatibility with `scripts/check-rfc-docs.mjs`). New RFCs SHOULD also set the `lifecycle` field — see AISDLC-118 — which captures the per-owner sign-off + implementation arc more precisely (Draft → Ready for Review → Signed Off → Implemented → Superseded). `Final` is a terminal pre-implementation status used by sign-off-gated RFCs (RFC-0006, RFC-0008) where the spec is locked but reference implementations are still in flight; `Implemented` is set after the spec lands in the normative documents.',
    },
    lifecycle: {
      type: 'string',
      enum: ['Draft', 'Ready for Review', 'Signed Off', 'Implemented', 'Superseded'],
      description:
        "AISDLC-118 lifecycle state, separate from the per-owner sign-off checklist in the RFC body. Drafts SHOULD land on main as soon as they're shareable so stakeholders can link to the canonical URL — sign-off no longer gates visibility. Values: `Draft` (initial brainstorm; structure may shift; sign-off boxes empty), `Ready for Review` (structure stable; awaiting sign-off; at least one owner signed), `Signed Off` (all owners signed; design locked), `Implemented` (corresponding milestone reached Done), `Superseded` (replaced by newer RFC; header notes the successor).",
    },
    author: {
      type: 'string',
      minLength: 1,
      description:
        'Primary author name(s). Comma-separated for multi-author RFCs (e.g. `Alexander Kline (Arcana Concept Studio), AI-SDLC Contributors`).',
    },
    created: {
      type: 'string',
      format: 'date',
      pattern: '^[0-9]{4}-[0-9]{2}-[0-9]{2}$',
      description: 'ISO 8601 date (YYYY-MM-DD) the RFC was first created.',
    },
    updated: {
      type: 'string',
      format: 'date',
      pattern: '^[0-9]{4}-[0-9]{2}-[0-9]{2}$',
      description: 'ISO 8601 date (YYYY-MM-DD) of the most recent substantive update.',
    },
    targetSpecVersion: {
      type: 'string',
      description: 'Spec API version this RFC targets (e.g. `v1alpha1`). Optional but recommended.',
    },
    requires: {
      type: 'array',
      items: { type: 'string', pattern: '^RFC-[0-9]{4}$' },
      description:
        'Other RFC IDs this RFC depends on (e.g. RFC-0006 requires RFC-0002 and RFC-0004). Optional.',
    },
    amends: {
      type: 'array',
      items: { type: 'string', pattern: '^RFC-[0-9]{4}$' },
      description:
        'Other RFC IDs this RFC amends (e.g. RFC-0010 amends RFC-0002 §3 and §5). Optional.',
    },
    requiresDocs: {
      type: 'array',
      uniqueItems: true,
      items: {
        type: 'string',
        enum: ['tutorial', 'operator-runbook', 'api-reference', 'getting-started', 'example'],
      },
      description:
        'Closed enum declaring which user-facing doc surfaces must reference this RFC. Each value maps to a `docs/` subdirectory: `tutorial` → `docs/tutorials/`, `operator-runbook` → `docs/operations/`, `api-reference` → `docs/api-reference/`, `getting-started` → `docs/getting-started/`, `example` → `docs/examples/`. The CI script (AISDLC-69.3) enforces that for each value in this array, at least one file in the corresponding subdirectory must reference the RFC by its `id` (e.g. literal text `RFC-0006`). An empty array (`[]`) is valid for purely strategic/conceptual RFCs (e.g. product strategy) and means CI does not check for any doc surface — the RFC body SHOULD explain why no user docs are required.',
    },
    deferredDocs: {
      type: 'boolean',
      default: false,
      description:
        "Escape hatch for RFCs whose `requiresDocs` surfaces are intentionally deferred (e.g. spec finalised but reference implementation in flight, so the runbook can't be written yet). When `true`, `deferredDocsDeadline` MUST also be set. CI passes but logs a warning that grows louder as the deadline approaches. NOTE: deadline enforcement is informational in v1; a future task may turn it into a hard gate.",
    },
    deferredDocsDeadline: {
      type: 'string',
      format: 'date',
      pattern: '^[0-9]{4}-[0-9]{2}-[0-9]{2}$',
      description:
        'ISO 8601 date by which the deferred docs MUST be authored. REQUIRED when `deferredDocs: true`.',
    },
  },
  allOf: [
    {
      if: { properties: { deferredDocs: { const: true } }, required: ['deferredDocs'] },
      then: { required: ['deferredDocsDeadline'] },
    },
  ],
} as const;

